// TypeScript implementation for Class Decorators
interface ClassDecoratorsPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processClassDecorators(item: ClassDecoratorsPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processClassDecorators({ id: 1, title: 'Class Decorators', status: 'active' }));

